parameters.jsCode:
const lead = $input.item.json;
const weekNum = lead.week_to_send;
const programPlan = typeof lead.program_plan === 'string' ? JSON.parse(lead.program_plan) : lead.program_plan;
const profile = typeof lead.user_profile === 'string' ? JSON.parse(lead.user_profile) : lead.user_profile;
const weekPlan = programPlan[`week_${weekNum}`];

const sessions = ['morning', 'midday', 'afternoon', 'evening'];
const weekPlanForPdf = {};
for (const s of sessions) {
  const slot = weekPlan[s] || {};
  weekPlanForPdf[s] = {
    warmup: slot.warmup ? {
      name: slot.warmup.name,
      description: slot.warmup.description,
      image_url: slot.warmup.image_url,
      cues: slot.warmup.cues
    } : null,
    main: slot.main ? {
      name: slot.main.name,
      description: slot.main.description,
      image_url: slot.main.image_url,
      cues: slot.main.cues
    } : null
  };
}

return { json: {
  lead_id: lead.id,
  name: lead.name,
  email: lead.email,
  week_number: weekNum,
  week_plan: weekPlanForPdf,
  profile: profile
} };

